# Fibonacci Number Using Recursion in C++

## Overview
This program calculates the nth Fibonacci number using recursive approach, with multiple implementations ranging from basic to optimized.

---

## Implementation

```cpp
#include <iostream>
#include <stdexcept>
#include <chrono>
#include <unordered_map>

// ============================================================
// 1. Basic Recursive Implementation (Simple but inefficient)
// ============================================================
long long fibBasic(int n) {
    // Base cases
    if (n == 0) return 0;
    if (n == 1) return 1;

    // Recursive case: F(n) = F(n-1) + F(n-2)
    return fibBasic(n - 1) + fibBasic(n - 2);
}

// ============================================================
// 2. Memoized Recursive Implementation (Optimized)
// ============================================================
long long fibMemo(int n, std::unordered_map<int, long long>& memo) {
    // Base cases
    if (n == 0) return 0;
    if (n == 1) return 1;

    // Check if already computed
    if (memo.find(n) != memo.end()) {
        return memo[n];
    }

    // Compute and store in memo table
    memo[n] = fibMemo(n - 1, memo) + fibMemo(n - 2, memo);
    return memo[n];
}

// Wrapper function for memoized version
long long fibMemoized(int n) {
    std::unordered_map<int, long long> memo;
    return fibMemo(n, memo);
}

// ============================================================
// 3. Input Validation Wrapper
// ============================================================
long long fibonacci(int n, bool useMemo = true) {
    if (n < 0) {
        throw std::invalid_argument("Input must be a non-negative integer.");
    }
    if (n > 92) {
        throw std::overflow_error("Result exceeds long long range for n > 92.");
    }

    return useMemo ? fibMemoized(n) : fibBasic(n);
}

// ============================================================
// 4. Helper: Print Fibonacci Series up to n terms
// ============================================================
void printFibSeries(int n) {
    std::cout << "\nFibonacci Series (first " << n + 1 << " terms):\n";
    for (int i = 0; i <= n; i++) {
        std::cout << "F(" << i << ") = " << fibMemoized(i);
        if (i < n) std::cout << ", ";
    }
    std::cout << "\n";
}

// ============================================================
// 5. Helper: Measure execution time
// ============================================================
void benchmarkComparison(int n) {
    if (n > 40) {
        std::cout << "\n[Skipping benchmark for n > 40 (basic recursion too slow)]\n";
        return;
    }

    std::cout << "\n--- Benchmark for F(" << n << ") ---\n";

    // Basic recursion timing
    auto start = std::chrono::high_resolution_clock::now();
    long long result1 = fibBasic(n);
    auto end = std::chrono::high_resolution_clock::now();
    auto duration1 = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << "Basic Recursion  : " << result1 << " | Time: " << duration1.count() << " µs\n";

    // Memoized recursion timing
    start = std::chrono::high_resolution_clock::now();
    long long result2 = fibMemoized(n);
    end = std::chrono::high_resolution_clock::now();
    auto duration2 = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << "Memoized Recursion: " << result2 << " | Time: " << duration2.count() << " µs\n";
}

